#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *X = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &X[i]);
        int minSize = N, maxSize = 1;
        int cur = 1;
        for (int i = 1; i < N; ++i) {
            if (X[i] - X[i-1] <= 2) ++cur;
            else {
                if (cur < minSize) minSize = cur;
                if (cur > maxSize) maxSize = cur;
                cur = 1;
            }
        }
        if (cur < minSize) minSize = cur;
        if (cur > maxSize) maxSize = cur;
        printf("%d %d\n", minSize, maxSize);
        free(X);
    }
    return 0;
}

