import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        X = [int(next(it)) for _ in range(N)]
        min_sz, max_sz = N, 1
        cur = 1
        for i in range(1, N):
            if X[i] - X[i-1] <= 2:
                cur += 1
            else:
                if cur < min_sz:
                    min_sz = cur
                if cur > max_sz:
                    max_sz = cur
                cur = 1
        if cur < min_sz:
            min_sz = cur
        if cur > max_sz:
            max_sz = cur
        out_lines.append(f"{min_sz} {max_sz}")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

